SELECT COUNT(*) AS QTD_PRODUCOES FROM LATTES_P_PRODBIB LPB JOIN LATTES_PRODBIB PB ON PB.PK = LPB.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPB.FK_SIAPE WHERE LOWER(PB.TIPO) = LOWER('artigo') AND LOWER(PB.NATUREZA) = LOWER('completo') AND LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%goiania%') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%filosofia%') AND PB.ANO = '2024'